class Playground {
    async run(inputs) {
        // Parse Input
        const rows = inputs[0].split(';').map(r => r.trim().split(',').map(v => parseInt(v.trim())));
        const N = rows.length;
        const M = rows[0].length;

        // Initialize Visuals
        this.grid.init(rows);
        this.visited.init(Array.from({length: N}, () => Array(M).fill(0)));
        this.sizes.init([]);
        this.stats.init([['Max Area', 0], ['Current Area', 0]]);
        this.log(`Grid size: ${N}x${M}`);
        await this.await();

        const getNeighbors = (r, c) => {
            const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
            const res = [];
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < N && nc >= 0 && nc < M) res.push([nr, nc]);
            }
            return res;
        };

        // 1. Component Labeling (BFS)
        const componentId = Array.from({ length: N }, () => Array(M).fill(0));
        const componentSize = new Map();
        let nextId = 2; 
        let maxIsland = 0;
        let hasZero = false;

        for (let r = 0; r < N; r++) {
            for (let c = 0; c < M; c++) {
                if (rows[r][c] === 1 && componentId[r][c] === 0) {
                    // Start BFS
                    this.log(`found Land at (${r},${c}). Starting BFS for Island ID ${nextId}`);
                    let size = 0;
                    componentId[r][c] = nextId;
                    this.visited.setCell(r, c, nextId);
                    this.visited.highlight(r, c, '#3b82f6');

                    const q = [[r,c]];
                    this.queue.enqueue(`[${r},${c}]`);
                    await this.await();

                    while (q.length > 0) {
                        const curr = q.shift();
                        const cr = curr[0];
                        const cc = curr[1];
                        this.queue.dequeue();
                        size++;

                        this.grid.highlight(cr, cc, '#3b82f6'); // Highlight in main grid too

                        for (const [nr, nc] of getNeighbors(cr, cc)) {
                            if (rows[nr][nc] === 1 && componentId[nr][nc] === 0) {
                                componentId[nr][nc] = nextId;
                                this.visited.setCell(nr, nc, nextId);
                                this.visited.highlight(nr, nc, '#60a5fa');
                                q.push([nr, nc]);
                                this.queue.enqueue(`[${nr},${nc}]`);
                                await this.await();
                            }
                        }
                    }

                    // Store Size
                    componentSize.set(nextId, size);
                    this.sizes.put(nextId, size);
                    this.log(`Island ${nextId} Size: ${size}`);
                    maxIsland = Math.max(maxIsland, size);
                    this.stats.put('Max Area', maxIsland);

                    // Cleanup Highlights
                    this.grid.clearHighlights();
                    this.visited.clearHighlights();
                    nextId++;
                } else if (rows[r][c] === 0) {
                    hasZero = true;
                }
            }
        }

        this.log(`Base Max Island Size: ${maxIsland}`);
        await this.await();
        if (!hasZero) return N * M;

        // 2. Try flipping 0s
        let possibleMax = maxIsland;

        for (let r = 0; r < N; r++) {
            for (let c = 0; c < M; c++) {
                if (rows[r][c] === 0) {
                    this.grid.highlight(r, c, '#f59e0b'); // Orange for testing flip
                    this.log(`Testing flip at (${r},${c}): Changing 0 to 1`);
                    await this.await();

                    const seenIds = new Set();
                    let currentSize = 1; // The flipped 0 itself
                    this.stats.put('Current Area', currentSize);
                    let formula = "1(flip)";

                    for (const [nr, nc] of getNeighbors(r, c)) {
                        const id = componentId[nr][nc];
                        if (id > 1 && !seenIds.has(id)) {
                            const size = componentSize.get(id);
                            currentSize += size;
                            this.stats.put('Current Area', currentSize);
                            seenIds.add(id);
                            formula += ` + ${size}(Island ${id})`;

                            this.log(`  -> Found neighbor (${nr},${nc}) of Island ${id}. Adding size ${size}`);
                            this.visited.highlight(nr, nc, '#f59e0b');
                            await this.await();
                        }
                    }

                    this.log(`  => Total Size = ${formula} = ${currentSize}`);
                    possibleMax = Math.max(possibleMax, currentSize);
                    this.stats.put('Max Area', possibleMax);

                    this.grid.highlight(r, c, ''); // Clear
                    this.visited.clearHighlights();
                }
            }
        }

        this.log(`Final Max Island Size: ${possibleMax}`);
        return possibleMax;
    }
}
